import java.util.*;class CircularTask{static class N{int id;String n;N next;N(int id,String n){this.id=id;this.n=n;}}static N head;static void add(int id,String n){N t=new N(id,n);if(head==null){head=t;t.next=t;}else{N c=head;while(c.next!=head)c=c.next;c.next=t;t.next=head;}}static void display(){if(head==null)return;N c=head;do{System.out.println(c.id+" "+c.n);c=c.next;}while(c!=head);}public static void main(String[] a){add(1,"T1");add(2,"T2");display();}}